import org.jetbrains.annotations.Nullable;
import org.jetbrains.mps.openapi.model.SNode;

/**
 * Represents an action to perform at the end of some intent scope.
 */
public interface IReconciliationAction {
  /**
   * Executes the current action. This will happen with appropriate model-access-levels.
   * 
   * If the context node of the action-scheduling is still available in the project, then the node-parameter will be that node.
   * Otherwise, the parameter will be non-existent / null.
   * 
   * @param node the context node from the scheduled action, or null if the node is gone by now
   */
  void execute(@Nullable SNode node);

  /**
   * This action type will take in a precalculated list of nodes at the time of scheduling
   * and once called, detach them all from their respective places in the AST.
   * This is especially useful if the node-of-reference at time of callback is already gone and doesn't allow further comparison.
   */
  final class DetachNodesAction implements IReconciliationAction {
    private final SNode[] nodesToDetach;
    public DetachNodesAction(SNode... nodesToDetach) {
      this.nodesToDetach = nodesToDetach;
    }
    @Override
    public void execute(@Nullable SNode node) {
      for (SNode n : nodesToDetach) {
        n.delete();
      }
    }
  }
}
